import{_ as a,o as e,c as t,V as s}from"./chunks/framework.d3b95951.js";const g=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-start.md","filePath":"guide/getting-start.md","lastUpdated":1693551551000}'),o={name:"guide/getting-start.md"},l=s('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><h2 id="unix" tabindex="-1">Unix 安装 <a class="header-anchor" href="#unix" aria-label="Permalink to &quot;Unix 安装{#unix}&quot;">​</a></h2><p>在大多数 Unix 系统(包括 macOS)上，您可以使用一个命令安装 Volta:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">curl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">https://get.volta.sh</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">bash</span></span></code></pre></div><p>对于 <a href="https://www.gnu.org/software/bash/" target="_blank" rel="noreferrer">bash</a>, <a href="https://www.zsh.org/" target="_blank" rel="noreferrer">zsh</a> 和 <a href="http://fishshell.com/" target="_blank" rel="noreferrer">fish</a>，这个安装程序将自动更新控制台启动脚本。如果您希望防止修改控制台启动脚本，请参阅跳过 Volta 设置。要手动配置你的 shell 使用 Volta，编辑你的控制台启动脚本如下:</p><ul><li>将 VOLTA_HOME 变量设置为$HOME/.volta <br></li><li>将$VOLTA_HOME/bin 添加到 PATH 变量的开头</li></ul><h2 id="windows-安装" tabindex="-1">Windows 安装 <a class="header-anchor" href="#windows-安装" aria-label="Permalink to &quot;Windows 安装&quot;">​</a></h2><p>对于 Windows，<a href="https://github.com/volta-cli/volta/releases/download/v1.1.1/volta-1.1.1-windows-x86_64.msi" target="_blank" rel="noreferrer">下载并运行 Windows 安装程序</a>并按照说明操作。</p><div class="tip custom-block"><p class="custom-block-title">提示</p><p>Volta 的功能依赖于创建符号链接，所以你必须:</p><ul><li>启用<a href="https://learn.microsoft.com/zh-cn/windows/apps/get-started/enable-your-device-for-development#accessing-settings-for-developers" target="_blank" rel="noreferrer">开发者模式</a>(推荐)</li><li>以提升的权限运行 Volta(不推荐)</li></ul></div><h2 id="windows-下的-linux-子系统" tabindex="-1">Windows 下的 linux 子系统 <a class="header-anchor" href="#windows-下的-linux-子系统" aria-label="Permalink to &quot;Windows 下的 linux 子系统&quot;">​</a></h2><p>如果您在 Linux 的 Windows 子系统中使用 Volta，请遵循上面的 Unix 安装指南。</p>',11),n=[l];function r(i,c,p,d,h,u){return e(),t("div",null,n)}const f=a(o,[["render",r]]);export{g as __pageData,f as default};
